// LESSON: JavaFX Lists and Tables - Reference Page 2.
// You will learn: Connect ObservableList data to ListView, selection, and TableView columns.
import javafx.application.Application;
import javafx.beans.property.SimpleIntegerProperty;
import javafx.beans.property.SimpleStringProperty;
import javafx.collections.FXCollections;
import javafx.collections.ObservableList;
import javafx.geometry.Insets;
import javafx.scene.Scene;
import javafx.scene.control.Label;
import javafx.scene.control.ListView;
import javafx.scene.control.TableColumn;
import javafx.scene.control.TableView;
import javafx.scene.layout.VBox;
import javafx.stage.Stage;

public class JavaFxListsTablesReference extends Application {
  public static void main(String[] args) {
    launch(args);
  }

  @Override
  public void start(Stage stage) {
    // EXAMPLE 1: ObservableList drives a ListView.
    ObservableList<String> names = FXCollections.observableArrayList();
    ListView<String> list = new ListView<>(names);
    names.add("Ada");
    names.add("Grace");
    // EXAMPLE 2: selectionModel reports the selected item.
    Label status = new Label("Choose a name");
    list.getSelectionModel().selectedItemProperty().addListener((obs, oldName, newName) -> {
      status.setText("Selected: " + newName);
    });
    // EXAMPLE 3: TableView shows object fields in columns.
    ObservableList<TablePerson> people = FXCollections.observableArrayList(new TablePerson("Ada", 17), new TablePerson("Grace", 18));
    TableView<TablePerson> table = new TableView<>(people);
    TableColumn<TablePerson, String> nameColumn = new TableColumn<>("Name");
    nameColumn.setCellValueFactory(cell -> new SimpleStringProperty(cell.getValue().name()));
    TableColumn<TablePerson, Number> ageColumn = new TableColumn<>("Age");
    ageColumn.setCellValueFactory(cell -> new SimpleIntegerProperty(cell.getValue().age()));
    table.getColumns().add(nameColumn);
    table.getColumns().add(ageColumn);
    VBox root = new VBox(8, status, list, table);
    root.setPadding(new Insets(12));
    stage.setScene(new Scene(root, 440, 360));
    stage.show();
  }
}

class TablePerson {
  private final String name;
  private final int age;

  TablePerson(String name, int age) {
    this.name = name;
    this.age = age;
  }

  String name() { return name; }
  int age() { return age; }
}
